import React from 'react';
import { useNavigate } from 'react-router-dom';
import { Button } from 'react-bootstrap';
import './Home.css';

const Home = () => {
  const navigate = useNavigate();

  return (
    <div className="home-container">
      <div className="home-content">
        <h1 className="home-title">
          Welcome to Centralized Employee Document Management System
        </h1>
        <p className="home-subtitle">
          Secure, fast, centralized HR document automation
        </p>
        <Button 
          variant="primary" 
          size="lg" 
          className="proceed-btn"
          onClick={() => navigate('/login')}
        >
          Proceed to Login
        </Button>
      </div>
      <footer className="home-footer">
        <p>&copy; {new Date().getFullYear()} Centralized Employee Document Management System. All rights reserved.</p>
      </footer>
    </div>
  );
};

export default Home;
